void UGPEffectCueHandler::UpdatePostEffectVectorParameters(struct FName PostEffectName, struct FName ParameterName, struct FLinearColor Value)
{
    static struct UFunction* Func = nullptr;
    if (!Func) Func = ClassPrivate->GetFunction("GPEffectCueHandler", "UpdatePostEffectVectorParameters");
    struct
    {
        struct FName PostEffectName;
        struct FName ParameterName;
        struct FLinearColor Value;
    } Parms{};
    Parms.PostEffectName = (struct FName)PostEffectName;
    Parms.ParameterName = (struct FName)ParameterName;
    Parms.Value = (struct FLinearColor)Value;
    this->ProcessEvent(Func, &Parms);
}

